#include<bits/stdc++.h>
using namespace std;
int n,m,ans,f[8388608],pow2[8388608];
const int mod=1e9+7;
int main()
{
    pow2[0]=1;
    for(int i=1;i<8388608;i++)
    {
        pow2[i]=pow2[i-1]*2%mod;
    }
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int c;
        scanf("%d",&c);
        int k=(1<<m)-1;
        for(int j=1;j<=c;j++)
        {
            int x;
            scanf("%d",&x);
            k^=(1<<(x-1));
        }
        f[k]++;
    }
    for(int i=1;i<=m;i++)
    {
        for(int j=0;j<(1<<m);j++)
        {
            if(j&(1<<(i-1)))
            {
                f[j^(1<<(i-1))]=(f[j^(1<<(i-1))]+f[j])%mod;
            }
        }
    }
    for(int i=0;i<(1<<m);i++)
    {
        int s=1;
        for(int j=1;j<=m;j++)
        {
            if(i&(1<<(j-1)))
            {
                s=-s;
            }
        }
        ans+=s*(pow2[f[i]]-1);
        ans%=mod;
    }
    ans=(ans+mod)%mod;
    printf("%d",ans);
    return 0;
}
